import "testing"

func TestAgeDays(t *testing.T) {
	const day = int64(86400)
	now := int64(100 * day)
	tests := []struct {
		name string
		then int64
		want int
	}{
		{"same instant", now, 0},
		{"one day ago", now - day, 1},
		{"ten days ago", now - 10*day, 10},
		{"never (zero) reads as epoch age", 0, 100},
		{"negative timestamp treated as never", -5, 100},
		{"future timestamp clamps to 0", now + day, 0},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if got := ageDays(now, tt.then); got != tt.want {
				t.Fatalf("ageDays(%d, %d) = %d, want %d", now, tt.then, got, tt.want)
			}
		})
	}
}

func TestStaleBackupsThresholds(t *testing.T) {
	dbPath := seedNovelStore(t)
	out := runNovelCmd(t, newNovelStaleBackupsCmd, "--local-days", "1", "--offsite-days", "3", "--db", dbPath)

	var rows []staleBackupRow
	mustUnmarshal(t, out, &rows)

	// glob-fs1 (10d old) is stale; glob-old is archived and excluded; the two
	// fresh Acme agents are not stale.
	if len(rows) != 1 {
		t.Fatalf("stale rows = %+v, want exactly glob-fs1", rows)
	}
	if rows[0].AgentName != "glob-fs1" || !rows[0].StaleLocal || !rows[0].StaleOffsite {
		t.Fatalf("unexpected stale row: %+v", rows[0])
	}
}
